        String[] actualHeadersArray = mrList.getHeadersList().toArray(new String[0]);
        Arrays.sort(expectedHeadersArray);
        Arrays.sort(actualHeadersArray);
        assertArrayEquals("List Headers don't match as expected", expectedHeadersArray, actualHeadersArray);
    }

