        Awaitility.await().atMost(10, TimeUnit.SECONDS).until(() ->
            !apiExecutor.findElementInShadowRoot("*>>tr[id='columnFilteringRow']", true).isEmpty());
        WebElement element = apiExecutor.findElementInShadowRoot("*>>tr[id='columnFilteringRow']", true).get(0);
        List<WebElement> listOfElements = element.findElements(By.tagName("td"));

        for (WebElement currentElement : listOfElements) {
            assertTrue("Current Element is not displayed", currentElement.isDisplayed());
        }
    }

